import React, { useState } from 'react';
import { Space, Input, Tag, Button } from '@universe-design/react';

export default {
  title: 'Components/Input/临时示例', // 注意：这里需要修改成自己对应 Component name。
  component: Input,
};

export function TextAreaSuffix() {
  const getLanguageTag = (disabled = false) => (
    <Tag size="extra-small" disabled={disabled} color={disabled ? 'neutral-option' : 'neutral-solid'}>
      English
    </Tag>
  );

  const value =
    '到公司担当奥德赛嘎嘎嘎过第三个按规定是对的sss到公司担当奥德赛嘎嘎嘎过第三个按规定是对的sss到公司担当奥德赛嘎嘎嘎过第三个按规定是对的sss到公司担当奥德赛嘎嘎嘎过第三个按规定是对的sss';
  return (
    <Space direction="vertical">
      <p>basic</p>
      <Input.TextArea placeholder="Basic usage" />
      <p>Count</p>
      <Input.TextArea showCount placeholder="Basic usage" />
      <p>Count and limit</p>
      <Input.TextArea showCount maxLength={200} placeholder="Basic usage" />
      <p>count and language tag</p>
      <Input.TextArea suffix={getLanguageTag()} showCount maxLength={20} placeholder="Basic usage" />
      <p>Disable</p>
      <Input.TextArea
        suffix={getLanguageTag(true)}
        showCount
        disabled
        rows={10}
        value={value}
        placeholder="Basic usage"
      />
    </Space>
  );
}
export function AutoResizeAdjust() {
  const [autoSize, setAutoSize] = useState(true);
  return (
    <>
      <p>Auto:{autoSize ? 'Auto' : ''} </p>
      <Input.TextArea
        style={{
          width: '40%',
        }}
        defaultValue={'a\nb'}
        placeholder="Basic 让人绕v  usage"
        rows={5}
        autoSize={autoSize}
      />
      <Button onClick={() => setAutoSize(!autoSize)}>autoSize开关</Button>
    </>
  );
}
